changeSet.sql:
ALTER TABLE qualitative_questions ADD COLUMN question_weight_id integer DEFAULT NULL;
ALTER TABLE qualitative_questions ADD CONSTRAINT fk_qualitative_questions_to_question_weight FOREIGN KEY (question_weight_id) REFERENCES question_weights (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION;
CREATE INDEX i_qualitative_question_weight ON qualitative_questions (question_weight_id);

ALTER TABLE metric_risks DROP COLUMN IF EXISTS question_weight_id;
